// SecureAuthService.js
import * as AuthSession from 'expo-auth-session';
import * as WebBrowser from 'expo-web-browser';
import { Platform } from 'react-native';

WebBrowser.maybeCompleteAuthSession();

const AUTH_CONFIG = {
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  tokenEndpoint: 'https://your-backend-api.com/auth/token', // YOUR BACKEND
  revocationEndpoint: 'https://your-backend-api.com/auth/revoke',
  clientId: 'mobile_app_client_123', // Public client ID only
  // NO CLIENT SECRET HERE
  redirectUri: AuthSession.makeRedirectUri({
    scheme: 'yourapp',
    path: 'oauth/callback'
  }),
  scopes: ['read', 'write', 'profile'],
  usePKCE: true, // REQUIRED for mobile apps
};

export const useSecureAuth = () => {
  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: AUTH_CONFIG.clientId,
      scopes: AUTH_CONFIG.scopes,
      redirectUri: AUTH_CONFIG.redirectUri,
      usePKCE: true,
      responseType: AuthSession.ResponseType.Code,
    },
    { authorizationEndpoint: AUTH_CONFIG.authorizationEndpoint }
  );

  const exchangeCodeForToken = async (code, codeVerifier) => {
    // Send to YOUR secure backend - never expose client secret
    const response = await fetch(AUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        code,
        code_verifier: codeVerifier,
        redirect_uri: AUTH_CONFIG.redirectUri,
        grant_type: 'authorization_code',
      }),
    });

    if (!response.ok) {
      throw new Error('Token exchange failed');
    }

    return await response.json();
  };

  return { request, response, promptAsync, exchangeCodeForToken };
};